var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NUN","text":{"KOREA":"이해했어요.","JPN":"理解しました。","ENG":"I understand now.","TWN":"我明白了。"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NUN","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NUN","text":{"KOREA":"당신은 저를 잡아서 돈을 벌려는 거잖아요.","JPN":"あなたが私を捕まえて一儲けするつもりだということを。","ENG":"You're planning to capture me and sell me off for money, aren't you?","TWN":"你是想抓我來賺錢吧。"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NUN","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"……그래. 난 널 잡아서 돈이랑 바꿔 먹을 생각이야.","JPN":"……そう。私はあんたを捕まえて売るつもり。","ENG":"...Yeah. I'm gonna turn you in and cash you out.","TWN":"……對，我是想抓你去換錢花。"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"에휴, 난 루시아 릿지. 수도원에서 퇴마를 담당하고 있어.","JPN":"はあ……私はルシア・リッジ。修道院でエクソシストをやっている。","ENG":"I'm Lucia Ridge. Exorcist nun from the monastery.","TWN":"哀，我是露西卡·李奇，在修道院負責驅魔。"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"카타리나라고 불러주세요.","JPN":"カタリナと呼んでください。","ENG":"Call me Katharina.","TWN":"請叫我卡特莉娜。"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그래. 카타리나.","JPN":"うん、カタリナ。","ENG":"Got it. Katharina.","TWN":"行，卡特莉娜。"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"여긴 뭘 훔치러 왔을까?","JPN":"ここには何を盗みに来たの？","ENG":"So, what exactly did you come here to steal?","TWN":"你是來這裡偷什麼的？"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"전 도둑이 아니에요!","JPN":"私は泥棒じゃありません！","ENG":"I'm no thief!","TWN":"我不是小偷！"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"저는 저주를 풀기 위해 여기 온 거라고요.","JPN":"呪いを解くためにここに来たんです。","ENG":"I came here to break a curse!","TWN":"我是為了解除詛咒才來的。"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"저주? 그건 너희들 전문이잖아.","JPN":"呪い？　それはあんたたちの専門じゃないか。","ENG":"A curse? That's your people's specialty, isn't it?","TWN":"詛咒？那可是你們的專長啊。"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"이곳에서 그 저주를 연구한다는 소문을 들었어요.","JPN":"ここでその呪いの研究をしているという噂を聞きました。","ENG":"I heard rumors that this place was researching the curse.","TWN":"我聽說這裡在研究那個詛咒。"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"언제까지고 성황청의 도움을 기다릴 수 없어서 그만…….","JPN":"いつまでも聖皇庁の助けを待つわけにはいかないと思って……","ENG":"I couldn't just sit around waiting for the Holy Curia to help... so I had no choice but to act on my own.","TWN":"不能再一直等待聖皇廳的幫助了……"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그래서 남의 저택에 무단 침입을 하셨다?","JPN":"それで人の邸宅に無断侵入をしたと。","ENG":"So you broke into someone's mansion instead?","TWN":"所以你擅自闖入了別人的屋子？"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"하, 하지만 나쁜 짓은 하지 않았어요.","JPN":"で、でも悪いことはしていません。","ENG":"B-but I didn't do anything bad!","TWN":"可，可是我沒有做壞事啊。"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"남의 피땀 흘린 연구 성과를 슬쩍하려고는 했겠지.","JPN":"人が苦労して研究した成果を横取りしようとはしたけどね。","ENG":"You were planning to snatch someone's hard-earned research, though.","TWN":"你是想竊取別人辛苦研究的成果吧。"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"뭐, 그건 나랑 상관없는 일이니까.","JPN":"まあ、でもそれは私とは関係ないことだから。","ENG":"Well, that's none of my business.","TWN":"唔，那與我無關。"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"네?","JPN":"はい？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"나는 악령을 퇴치하고, 돈만 받으면 되거든.","JPN":"私は悪霊を退治して、報酬をもらえればそれでいいから。","ENG":"I just exorcise evil spirits and get paid for it.","TWN":"我只負責驅除惡靈，拿錢就行。"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"의뢰인의 연구 성과를 도둑 맞든 말든 내가 신경 쓸 건 아니라고 할까?","JPN":"依頼人の研究の成果が盗まれようが、知ったことではないってこと。","ENG":"Whether my client's research gets stolen or not? Not my problem.","TWN":"委託人的研究成果被偷也好，沒被偷也罷，這跟我有什麼關係？"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그건 그렇고, 아까 왜 그랬던 거야?","JPN":"ところであんた、さっきのは何だったの？","ENG":"Now, about earlier. What was that about?","TWN":"話說回來，剛才你為什麼那麼做？"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"혹시, 갑자기 몸이 끓는 것처럼 뜨겁다던가…….","JPN":"もしかして、急に体が燃えるように熱くなったり……","ENG":"Did your body suddenly feel like it was burning up?","TWN":"你有沒有突然覺得身體像是在沸騰一樣熱？"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"……몸이 뜨겁진 않아요.","JPN":"……体が熱くなったりはしません。","ENG":"...No. My body wasn't hot.","TWN":"……身體不熱。"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그저 간절하게 남의 피를 탐하는 것뿐이죠.","JPN":"ただ、人の血が欲しくてたまらなくなるだけです。","ENG":"I just... crave other people's blood. Desperately.","TWN":"只是急切地渴望他人的鮮血而已。"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그게 저주의 전부예요.","JPN":"それが、私の呪い。","ENG":"That's the curse.","TWN":"那就是詛咒。"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};